 Mobile','COD Mobile CP recharge.',['80 CP'=>99,'420 CP'=>499,'880 CP'=>999]],['Steam Gift Card','Steam wallet gift cards.',['₹500 Gift Card'=>500,'₹1000 Gift Card'=>1000,'₹2000 Gift Card'=>2000]]];foreach($games as $idx=>$row){[$name,$desc,$packs]=$row;$game=Game::firstOrCreate(['slug'=>Str::slug($name)],['category_id'=>$cat->id,'name'=>$name,'description'=>$desc,'image'=>'','cover_3d'=>'','is_active'=>1,'requires_server_id'=>in_array($name,['Mobile Legends']),'requires_player_id'=>1,'sort_order'=>$idx+1]);$i=1;foreach($packs as $p=>$price){GamePackage::firstOrCreate(['sku'=>strtoupper(Str::slug($name.'-'.$p,'_'))],['game_id'=>$game->id,'provider_id'=>$provider->id,'name'=>$p,'price_minor'=>(int)round($price*100),'currency_code'=>'INR','credit_label'=>$p,'provider_product_id'=>strtoupper(Str::slug($game->slug.'-'.$p,'_')),'delivery_mode'=>'uid_topup','image'=>'','is_active'=>1,'sort_order'=>$i++]);}}Banner::firstOrCreate(['title'=>'Instant Game Top-Up'],['subtitle'=>'Buy diamonds, UC, Robux, Minecoins and gift cards in seconds.','image'=>'','button_text'=>'Browse Games','button_url'=>'#games','placement'=>'home','sort_order'=>1,'is_active'=>1]);Video::firstOrCreate(['title'=>'How to top up'],['youtube_url'=>'https://www.youtube.com/embed/dQw4w9WgXcQ','placement'=>'home','sort_order'=>1,'is_active'=>1]);Setting::firstOrCreate(['group_key'=>'site','item_key'=>'currency'],['value'=>'INR','type'=>'text','is_public'=>1]);}}
